import { useEffect, useState } from "react";
import "../styles/Posts.css";

export default function ReferencePicker({ references, setReferences }) {
    const [query, setQuery] = useState("");
    const [results, setResults] = useState([]);


    const REF_BADGE_MAP = {
        CLUB: "badge--yellow",
        EVENT: "badge--purple",
        THREAD: "badge--blue",
        USER: "badge--yellow",
        POST: "badge--indigo",
        DEFAULT: "badge--gray",
    };

    const getRefBadgeClass = (type) =>
        REF_BADGE_MAP[type] ?? REF_BADGE_MAP.DEFAULT;


    useEffect(() => {
        if (!query.trim()) {
            setResults([]);
            return;
        }

        const controller = new AbortController();

        fetch(`/api/posts/references/search?q=${encodeURIComponent(query)}`, {
            signal: controller.signal
        })
            .then(res => res.json())
            .then(data => setResults(data))
            .catch(() => {});

        return () => controller.abort();
    }, [query]);

    const addReference = (ref) => {
        if (
            references.some(
                r => r.type === ref.type && r.targetId === ref.targetId
            )
        ) return;

        setReferences(prev => [...prev, ref]);
        setQuery("");
        setResults([]);
    };

    const removeReference = (idx) => {
        setReferences(prev => prev.filter((_, i) => i !== idx));
    };

    return (
        <div className="reference-picker">
            <input
                className={"reference-textbox"}
                placeholder="Reference"
                value={query}
                onChange={e => setQuery(e.target.value)}
            />

            {results.length > 0 && (
                <div className="reference-results">
                    {results.map((r, i) => (
                        <div
                            key={i}
                            className="reference-result"
                            onClick={() => addReference(r)}
                        >
                            {r.displayText}
                            <span className="type">{r.type}</span>
                        </div>
                    ))}
                </div>
            )}

            {references.length > 0 && (
                <div className={`badge post-reference ${getRefBadgeClass(ref.type)}`}>
                    {references.map((r, i) => (
                        <span key={i} onClick={() => removeReference(i)}>
              @{r.displayText} ✕
            </span>
                    ))}
                </div>
            )}
        </div>
    );
}
